SELECT count(*) FROM movie_info, title, info_type, cast_info, role_type, movie_keyword, movie_companies, keyword, company_name WHERE movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id AND cast_info.movie_id = title.id AND cast_info.role_id = role_type.id AND movie_keyword.movie_id = title.id AND movie_companies.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND movie_companies.company_id = company_name.id;